      "content": "declare const require: any;
declare const process: any;

interface Task {
  id: string;
  title: string;
  done: boolean;
  createdAt: string;
  doneAt?: string;
}

class TaskStore {
  private filePath: string;
  private tasks: Task[] = [];

  constructor(filePath: string) {
    this.filePath = filePath;
    this.load();
  }

  private load() {
    try {
      const data = require('node:fs').readFileSync(this.filePath, 'utf8');
      const obj = JSON.parse(data);
      this.tasks = obj.tasks || [];
    } catch (error) {
      if (error.code !== 'ENOENT') {
        console.error(error);
      }
      this.tasks = [];
    }
  }

  private save() {
    const data = JSON.stringify({ tasks: this.tasks }, null, 2);
    require('node:fs').writeFileSync(this.filePath, data, 'utf8');
  }

  list(): Task[] {
    return this.tasks.slice();
  }

  add(title: string): Task {
    const task: Task = {
      id: require('node:crypto').randomUUID(),
      title,
      done: false,
      createdAt: new Date().toISOString(),
    };
    this.tasks.push(task);
    this.save();
    return task;
  }

  done(id: string): Task {
    const task = this.tasks.find(t => t.id === id);
    if (!task) return null as any;
    task.done = true;
    task.doneAt = new Date().toISOString();
    this.save();
    return task;
  }

  remove(id: string): Task {
    const index = this.tasks.findIndex(t => t.id === id);
    if (index === -1) return null as any;
    const removed = this.tasks.splice(index, 1)[0];
    this.save();
    return removed;
  }
}

module.exports = { TaskStore };
