declare const process: any;

const fs = require('node:fs');
const path = require('node:path');
const crypto = require('node:crypto');

function printHelp() {
  console.log(`
Todo CLI

Usage:
  node dist/cli.js --help
  node dist/cli.js list --data <path>
  node dist/cli.js add <title> --data <path>
  node dist/cli.js done <id> --data <path>
  node dist/cli.js remove <id> --data <path>

All commands output JSON with an \(ok\) field.
`);
}

function runCommand(cmd: string, args: string[], dataPath: string) {
  let output: any = { ok: true };
  try {
    switch (cmd) {
      case 'list': {
        const tasks = JSON.parse(fs.readFileSync(dataPath, 'utf8')).tasks || [];
        output = { ok: true, tasks };
        break;
      }
      case 'add': {
        if (args.length === 0) throw new Error('Missing title');
        const title = args.join(' ');
        const tasks = JSON.parse(fs.readFileSync(dataPath, 'utf8')).tasks || [];
        const newTask = {
          id: crypto.randomUUID(),
          title,
          done: false,
          createdAt: new Date().toISOString(),
        };
        tasks.push(newTask);
        fs.writeFileSync(dataPath, JSON.stringify({ tasks }, null, 2), 'utf8');
        output = { ok: true, task: newTask };
        break;
      }
      case 'done': {
        if (args.length === 0) throw new Error('Missing id');
        const id = args[0];
        const data = JSON.parse(fs.readFileSync(dataPath, 'utf8'));
        const tasks = data.tasks || [];
        const task = tasks.find(t => t.id === id);
        if (!task) throw new Error('Task not found');
        task.done = true;
        task.doneAt = new Date().toISOString();
        fs.writeFileSync(dataPath, JSON.stringify(data, null, 2), 'utf8');
        output = { ok: true, task };
        break;
      }
      case 'remove': {
        if (args.length === 0) throw new Error('Missing id');
        const id = args[0];
        const data = JSON.parse(fs.readFileSync(dataPath, 'utf8'));
        const tasks = data.tasks || [];
        const index = tasks.findIndex(t => t.id === id);
        if (index === -1) throw new Error('Task not found');
        const [removed] = tasks.splice(index, 1);
        fs.writeFileSync(dataPath, JSON.stringify(data, null, 2), 'utf8');
        output = { ok: true, task: removed };
        break;
      }
      default:
        output = { ok: false, error: 'Unknown command' };
    }
  } catch (error: any) {
    output = { ok: false, error: error.message || String(error) };
  }
  console.log(JSON.stringify(output));
}

function main() {
  const argv = process.argv.slice(2);
  if (argv.length === 0) {
    printHelp();
    return;
  }

  const cmd = argv[0];
  if (cmd === '--help' || cmd === '-h') {
    printHelp();
    return;
  }

  const hasData = argv.includes('--data');
  if (!hasData) {
    console.error('Error: --data argument is required');
    process.exit(1);
  }

  const dataIndex = argv.indexOf('--data');
  const dataPath = argv[dataIndex + 1];
  if (!dataPath) {
    console.error('Error: missing value for --data');
    process.exit(1);
  }

  const args = argv.slice(1);
  // Remove --data and its value from args
  const filteredArgs = [];
  for (let i = 0; i < args.length; i++) {
    if (args[i] === '--data') {
      i++; // skip value
    } else {
      filteredArgs.push(args[i]);
    }
  }

  runCommand(cmd, filteredArgs, dataPath);
}

if (require.main === module) {
  main();
}

module.exports = { main };
